	this.tagsIndex = createTagsIndex(this.app);
	this.propsIndex = createPropsIndex(this.app);
	await Promise.all([
		this.filesIndex.refresh(),
		this.tagsIndex.refresh(),
		this.propsIndex.refresh(),
	]);
	PerfMeter.mark('vaultman:boot:index-refresh:end');

