import type { App } from 'obsidian';
import type { FileNode, IFilesIndex } from '../types/typeContracts';
import { createNodeIndex } from './indexNodeCreate';

export function createFilesIndex(app: App): IFilesIndex {
	return createNodeIndex<FileNode>({
		build: () =>
			(app.vault.getFiles?.() ?? app.vault.getMarkdownFiles()).map((file) => ({
				id: file.path,
				path: file.path,
				basename: file.basename,
				file,
			})),
	});
}

import type { App } from 'obsidian';
import type { TagNode, ITagsIndex } from '../types/typeContracts';
import { createNodeIndex } from './indexNodeCreate';

export function createTagsIndex(app: App): ITagsIndex {
	return createNodeIndex<TagNode>({
		build: () => {
			const cache = app.metadataCache as any;
			const rawTags: Record<string, number> =
				typeof cache.getTags === 'function' ? cache.getTags() : {};

			let entries: [string, number][];
			if (Object.keys(rawTags).length > 0) {
				entries = Object.entries(rawTags);
			} else {
				// Fallback to manual scan if getTags() is empty or missing
				const counts = new Map<string, number>();
				for (const file of app.vault.getMarkdownFiles()) {
					const fileCache = app.metadataCache.getFileCache(file);
					if (!fileCache) continue;
					const tags = (fileCache.tags ?? []).map((t) => t.tag);
					for (const t of tags) {
						counts.set(t, (counts.get(t) ?? 0) + 1);
					}
				}
				entries = Array.from(counts.entries());
			}

			return entries.map(([tag, count]) => ({
				id: tag,
				tag,
				count,
				parent: tag.includes('/')
					? '#' + tag.slice(1).split('/').slice(0, -1).join('/')
					: undefined,
			}));
		},
	});
}

import type { App } from 'obsidian';
import type { IPropsIndex, PropNode } from '../types/typeContracts';
import { createNodeIndex } from './indexNodeCreate';

export function createPropsIndex(app: App): IPropsIndex {
	return createNodeIndex<PropNode>({
		build: () => {
			const acc = new Map<string, { values: Map<string, number>; files: Set<string> }>();
			for (const file of app.vault.getMarkdownFiles()) {
				const fm = app.metadataCache.getFileCache(file)?.frontmatter;
				if (!fm) continue;
				for (const [key, val] of Object.entries(fm)) {
					if (key === 'position') continue;
					let entry = acc.get(key);
					if (!entry) {
						entry = { values: new Map(), files: new Set() };
						acc.set(key, entry);
					}
					entry.files.add(file.path);
					const vals = Array.isArray(val) ? val : [val];
					for (const v of vals) {
						if (v == null) continue;
						const str = String(v);
						entry.values.set(str, (entry.values.get(str) ?? 0) + 1);
					}
				}
			}
			return Array.from(acc.entries()).map(([property, e]) => ({
				id: property,
				property,
				values: Array.from(e.values.keys()),
				valueFrequencies: Object.fromEntries(e.values),
				fileCount: e.files.size,
			}));
		},
	});
}

